    { titulo: 'Oficial Investigador — criação, aproveitamento e curso de formação', status: 'Depende de edital e ato oficial', ano: 'Lei CE 19.706/2026', tipo: 'individual/coletivo', desc: 'A Lei CE nº 19.706/2026 cria cargos e amplia aproveitamento, mas não garante posse automática. Questões sobre convocação, classificação, cotas, documentação, curso de formação e nomeação dependem dos editais e publicações oficiais.', base: 'Lei CE nº 19.706/2026, Edital nº 1-PC/CE/2025, comunicados CEV/UECE, DOE/CE e atos da SSPDS/SEPLAG.', fonte: 'ALECE / CEV-UECE / DOE-CE', fonteUrl: 'https://www2.al.ce.gov.br/legislativo/legislacao5/leis2026/19706.htm', atualizado: 'Maio/2026' },
    { titulo: 'Delegado PCCE — concurso, nomeação e remuneração inicial', status: 'Conferência por edital', ano: 'Edital 2025/2026', tipo: 'individual', desc: 'Demandas podem envolver prova, oral, títulos, investigação social, TAF, avaliação médica, cotas, curso de formação, nomeação e posse. Remuneração inicial deve ser conferida no edital e no ato de ingresso.', base: 'Edital Cebraspe PCCE Delegado 2025, Lei CE nº 12.124/1993, Lei Orgânica Nacional das Polícias Civis, DOE/CE e atos de nomeação.', fonte: 'Cebraspe / Governo do Ceará / SEPLAG-CE', fonteUrl: 'https://cdn.cebraspe.org.br/concursos/pc_ce_25_delegado/arquivos/Ed_1_2025_PC_CE_Delegado_Abertura.pdf', atualizado: 'Maio/2026' },
    { titulo: 'Plantões, adicional noturno, diárias e funções', status: 'Depende de escala e rubrica', ano: 'Tema permanente', tipo: 'individual', desc: 'Verificar jornada, escala, plantão, adicional noturno, diárias, função de chefia, acúmulo, cumprimento efetivo, natureza da parcela, reflexos e pagamentos no contracheque.', base: 'Estatuto da Polícia Civil do Ceará, leis estaduais, atos PCCE/SSPDS/SEPLAG, escala, ordem de serviço, portaria de designação, Diário Oficial e ficha financeira.', fonte: 'PCCE / SSPDS-CE / DOE-CE', fonteUrl: 'https://www.policiacivil.ce.gov.br/', atualizado: 'Maio/2026' },
    { titulo: 'Aposentadoria policial, abono de permanência e paridade/integralidade', status: 'Análise previdenciária individual', ano: 'EC 103/2019 e regras policiais', tipo: 'individual', desc: 'Exige análise da data de ingresso, idade, tempo policial, tempo total, cargo, regra de transição, ato de aposentadoria, abono de permanência, contribuição e cálculo aplicado pelo RPPS estadual.', base: 'LC Federal nº 51/1985, LC Federal nº 144/2014, EC nº 103/2019, Lei Orgânica Nacional das Polícias Civis, legislação estadual do Ceará, CEPREV e registros funcionais.', fonte: 'CEPREV/CE / PCCE / legislação previdenciária', fonteUrl: 'https://www.ceara.gov.br/', atualizado: 'Maio/2026' }
